// ============================================================================
// FileListItem Widget
// ============================================================================
// A single file item in a file list (staged/changed files section)
// Features: file icon, filename/path display, status badge (M/A/D/R),
//           action button (stage/unstage), discard button, selection/hover states

// Forward declaration of FileList
struct FileList;

// File status enum (mirrors platform.cpp FileStatus)
enum class FileListItemStatus { Modified, Added, Deleted, Renamed, Untracked };

// External functions from platform.cpp (for file icons and text layout)
extern ID2D1Bitmap* get_file_icon(const wchar_t* filename);
extern void draw_file_icon(ID2D1Bitmap* bitmap, float x, float y, float size);
extern IDWriteTextFormat* g_text_format_mono;
extern IDWriteTextFormat* g_text_format_path;

// Helper: get status color
static uint32_t file_list_get_status_color(FileListItemStatus status) {
    switch (status) {
        case FileListItemStatus::Modified:  return Theme::STATUS_MODIFIED;
        case FileListItemStatus::Added:     return Theme::STATUS_ADDED;
        case FileListItemStatus::Deleted:   return Theme::STATUS_DELETED;
        case FileListItemStatus::Renamed:   return Theme::STATUS_RENAMED;
        case FileListItemStatus::Untracked: return Theme::STATUS_ADDED;
        default:                            return Theme::TEXT_MUTED;
    }
}

// Helper: get status character for badge
static wchar_t file_list_get_status_char(FileListItemStatus status) {
    switch (status) {
        case FileListItemStatus::Modified:  return L'M';
        case FileListItemStatus::Added:     return L'A';
        case FileListItemStatus::Deleted:   return L'D';
        case FileListItemStatus::Renamed:   return L'R';
        case FileListItemStatus::Untracked: return L'?';
        default:                            return L' ';
    }
}

// Helper: create text layout with ellipsis trimming (for filename/path)
static IDWriteTextLayout* file_list_create_text_layout_ellipsis(
    const wchar_t* text,
    IDWriteTextFormat* format,
    float max_width,
    float max_height
) {
    if (!text || !format || !g_dwrite_factory) return nullptr;

    IDWriteTextLayout* layout = nullptr;
    HRESULT hr = g_dwrite_factory->CreateTextLayout(
        text,
        (UINT32)wcslen(text),
        format,
        max_width,
        max_height,
        &layout
    );

    if (SUCCEEDED(hr) && layout) {
        layout->SetWordWrapping(DWRITE_WORD_WRAPPING_NO_WRAP);

        DWRITE_TRIMMING trimming = {};
        trimming.granularity = DWRITE_TRIMMING_GRANULARITY_CHARACTER;
        trimming.delimiter = 0;
        trimming.delimiterCount = 0;

        IDWriteInlineObject* ellipsis = nullptr;
        g_dwrite_factory->CreateEllipsisTrimmingSign(layout, &ellipsis);
        layout->SetTrimming(&trimming, ellipsis);
        if (ellipsis) ellipsis->Release();
    }

    return layout;
}

struct FileListItem : Widget {
    // File data
    wchar_t filename[256] = {};      // Just the filename
    wchar_t full_path[512] = {};     // Full relative path
    wchar_t old_path[512] = {};      // Original path for renames (empty if not rename)
    FileListItemStatus status = FileListItemStatus::Modified;
    uint8_t similarity = 0;          // Rename similarity percentage (0-100)
    int file_index = -1;             // Index in the file list
    bool is_staged = false;          // True if in staged section, false if in changed section

    // State
    bool selected = false;
    bool action_hovered = false;     // Stage/unstage button hovered
    bool discard_hovered = false;    // Discard button hovered (for changed files)
    bool show_keyboard_focus = false; // Set by parent FileList when rendering
    bool hide_action_buttons = false; // Hide stage/unstage/discard buttons (for commit view)

    // Appearance
    float item_height = Sidebar::FILE_ITEM_HEIGHT_V2;  // 42.0f
    float icon_size = Sidebar::FILE_ICON_SIZE;         // 16.0f
    float icon_padding = Sidebar::FILE_ICON_PADDING;   // 8.0f
    float badge_size = Sidebar::STATUS_BADGE_SIZE;     // 18.0f
    float badge_radius = Sidebar::STATUS_BADGE_RADIUS; // 3.0f
    float action_btn_size = 18.0f;
    float discard_btn_size = Sidebar::DISCARD_BUTTON_SIZE;  // 16.0f

    // Colors (using theme)
    uint32_t selection_bg = Theme::ACCENT;             // 12% opacity for selection bg
    uint32_t selection_border = Theme::SELECTION_BORDER;
    uint32_t hover_bg = Theme::BG_HOVER;

    // Callbacks
    void (*on_select)(FileListItem* item, void* user_data) = nullptr;
    void (*on_action)(FileListItem* item, void* user_data) = nullptr;    // Stage/unstage
    void (*on_discard)(FileListItem* item, void* user_data) = nullptr;   // Discard changes
    void (*on_dbl_click_cb)(FileListItem* item, void* user_data) = nullptr;  // Open diff (renamed to avoid name collision with virtual method)
    void (*on_context_menu)(FileListItem* item, float screen_x, float screen_y, void* user_data) = nullptr;  // Right-click context menu
    void* user_data = nullptr;

    // Parent file list (for virtualization info)
    FileList* parent_list = nullptr;

    FileListItem() {
        preferred_height = item_height;
        height_mode = SizeMode::Fixed;
    }

    void measure(const LayoutConstraints& constraints) override {
        preferred_height = item_height;
        preferred_width = constraints.max_width;
        rect.width = preferred_width;
        rect.height = preferred_height;
    }

    void render(RenderContext& ctx) override {
        float height = rect.height;
        D2D1_RECT_F bg_rect = D2D1::RectF(
            rect.x, rect.y,
            rect.x + rect.width, rect.y + height
        );

        // Background (selection/hover)
        if (selected) {
            D2D1_COLOR_F sel_color = color_from_argb(selection_bg);
            sel_color.a = 0.12f;
            ctx.brush->SetColor(sel_color);
            ctx.target->FillRectangle(bg_rect, ctx.brush);

            // Selection border (left edge)
            D2D1_RECT_F border_rect = D2D1::RectF(rect.x, rect.y, rect.x + 2.0f, rect.y + height);
            ctx.fill_rect(border_rect, selection_border);

            // Focus ring when parent has keyboard focus
            // Note: parent_list->flags requires FileList to be complete, so we store
            // this info in a boolean that FileList sets before rendering
            if (show_keyboard_focus) {
                D2D1_RECT_F focus_rect = D2D1::RectF(
                    rect.x + 2.0f, rect.y + 1.0f,
                    rect.x + rect.width - 2.0f, rect.y + height - 1.0f);
                ctx.brush->SetColor(color_from_argb(Theme::ACCENT));
                D2D1_ROUNDED_RECT rr = { focus_rect, 3.0f, 3.0f };
                ctx.target->DrawRoundedRectangle(rr, ctx.brush, 2.0f);
            }
        } else if (flags & WidgetFlags::Hovered) {
            ctx.fill_rect(bg_rect, hover_bg);
        }

        float x = rect.x + Theme::PADDING;

        // Discard button (only on hover for changed files, left side)
        bool show_discard = !is_staged && (flags & WidgetFlags::Hovered) && !hide_action_buttons;
        if (show_discard) {
            float discard_y = rect.y + (height - discard_btn_size) / 2.0f;

            uint32_t discard_color = discard_hovered ? 0xFFF14C4C : Theme::TEXT_MUTED;
            ctx.brush->SetColor(color_from_argb(discard_color));

            // Draw X icon (two diagonal lines)
            float cx = x + discard_btn_size / 2.0f;
            float cy = discard_y + discard_btn_size / 2.0f;
            float r = 4.0f;
            ctx.target->DrawLine(D2D1::Point2F(cx - r, cy - r), D2D1::Point2F(cx + r, cy + r), ctx.brush, 1.5f);
            ctx.target->DrawLine(D2D1::Point2F(cx - r, cy + r), D2D1::Point2F(cx + r, cy - r), ctx.brush, 1.5f);

            x += discard_btn_size + Theme::PADDING_SMALL;
        }

        // File icon
        ID2D1Bitmap* icon = get_file_icon(filename);
        if (icon) {
            float icon_y = rect.y + (height - icon_size) / 2.0f;
            draw_file_icon(icon, x, icon_y, icon_size);
        }
        x += icon_size + icon_padding;

        // Calculate text width (leave room for badge + action button)
        float action_space = (flags & WidgetFlags::Hovered) ? (action_btn_size + Theme::PADDING_SMALL) : 0.0f;
        float right_margin = badge_size + Theme::PADDING + 4.0f + action_space;
        float text_width = rect.width - (x - rect.x) - right_margin;

        // Line 1: Filename
        IDWriteTextLayout* filename_layout = file_list_create_text_layout_ellipsis(
            filename, g_text_format_mono, text_width, 20.0f);
        if (filename_layout) {
            ctx.brush->SetColor(color_from_argb(Theme::TEXT_PRIMARY));
            ctx.target->DrawTextLayout(
                D2D1::Point2F(x, rect.y + Sidebar::FILE_LINE1_OFFSET),
                filename_layout, ctx.brush);
            filename_layout->Release();
        }

        // Line 2: Path (directory only) or "old → new" for renames
        wchar_t path_text[512] = L"";
        if (status == FileListItemStatus::Renamed && old_path[0] != L'\0') {
            // For renames, show "old_name → new_name"
            const wchar_t* old_slash = wcsrchr(old_path, L'/');
            const wchar_t* old_backslash = wcsrchr(old_path, L'\\');
            const wchar_t* old_sep = (old_slash > old_backslash) ? old_slash : old_backslash;
            const wchar_t* old_name = old_sep ? (old_sep + 1) : old_path;
            swprintf_s(path_text, 512, L"%s \x2192 %s", old_name, filename);  // Unicode arrow →
        } else if (full_path[0] != L'\0') {
            const wchar_t* last_slash = wcsrchr(full_path, L'/');
            const wchar_t* last_backslash = wcsrchr(full_path, L'\\');
            const wchar_t* separator = (last_slash > last_backslash) ? last_slash : last_backslash;

            if (separator && separator != full_path) {
                size_t dir_len = separator - full_path;
                if (dir_len < 512) {
                    wcsncpy_s(path_text, 512, full_path, dir_len);
                    path_text[dir_len] = L'\0';
                }
            }
        }

        if (path_text[0] != L'\0') {
            IDWriteTextLayout* path_layout = file_list_create_text_layout_ellipsis(
                path_text, g_text_format_path, text_width, 16.0f);
            if (path_layout) {
                ctx.brush->SetColor(color_from_argb(Theme::TEXT_MUTED));
                ctx.target->DrawTextLayout(
                    D2D1::Point2F(x, rect.y + Sidebar::FILE_LINE2_OFFSET),
                    path_layout, ctx.brush);
                path_layout->Release();
            }
        }

        // Status badge (right side)
        float badge_x = rect.x + rect.width - badge_size - Theme::PADDING;
        float badge_y = rect.y + (height - badge_size) / 2.0f;

        uint32_t status_color = file_list_get_status_color(status);
        D2D1_ROUNDED_RECT badge_rect = D2D1::RoundedRect(
            D2D1::RectF(badge_x, badge_y, badge_x + badge_size, badge_y + badge_size),
            badge_radius, badge_radius);

        // Badge background (20% opacity)
        D2D1_COLOR_F badge_bg = color_from_argb(status_color);
        badge_bg.a = 0.2f;
        ctx.brush->SetColor(badge_bg);
        ctx.target->FillRoundedRectangle(badge_rect, ctx.brush);

        // Badge character
        wchar_t status_char = file_list_get_status_char(status);
        D2D1_RECT_F char_rect = D2D1::RectF(badge_x, badge_y, badge_x + badge_size, badge_y + badge_size);
        if (g_text_format_badge) {
            ctx.draw_text(&status_char, 1, g_text_format_badge, char_rect, status_color);
        }

        // Action button (+/-) on hover (to left of badge)
        if ((flags & WidgetFlags::Hovered) && !hide_action_buttons) {
            float action_x = badge_x - action_btn_size - Theme::PADDING_SMALL;
            float action_y = rect.y + (height - action_btn_size) / 2.0f;

            D2D1_ROUNDED_RECT action_rect = D2D1::RoundedRect(
                D2D1::RectF(action_x, action_y, action_x + action_btn_size, action_y + action_btn_size),
                3.0f, 3.0f);

            uint32_t btn_bg = action_hovered ? Theme::ACCENT : Theme::BG_TERTIARY;
            ctx.brush->SetColor(color_from_argb(btn_bg));
            ctx.target->FillRoundedRectangle(action_rect, ctx.brush);

            // Draw +/- symbol
            wchar_t symbol = is_staged ? L'-' : L'+';
            uint32_t symbol_color = action_hovered ? 0xFFFFFFFF : Theme::TEXT_SECONDARY;
            D2D1_RECT_F symbol_rect = D2D1::RectF(action_x, action_y, action_x + action_btn_size, action_y + action_btn_size);
            if (g_text_format_badge) {
                ctx.draw_text(&symbol, 1, g_text_format_badge, symbol_rect, symbol_color);
            }
        }
    }

    bool on_mouse_move(float x, float y) override {
        (void)y;

        bool was_action_hovered = action_hovered;
        bool was_discard_hovered = discard_hovered;

        action_hovered = false;
        discard_hovered = false;

        // Skip button hover detection if action buttons are hidden
        if (!hide_action_buttons) {
            // Check action button hover
            float badge_x = rect.width - badge_size - Theme::PADDING;
            float action_x = badge_x - action_btn_size - Theme::PADDING_SMALL;
            float action_y = (rect.height - action_btn_size) / 2.0f;

            if (x >= action_x && x < action_x + action_btn_size &&
                y >= action_y && y < action_y + action_btn_size) {
                action_hovered = true;
            }

            // Check discard button hover (only for changed files)
            if (!is_staged) {
                float discard_x = Theme::PADDING;
                float discard_y_pos = (rect.height - discard_btn_size) / 2.0f;

                if (x >= discard_x && x < discard_x + discard_btn_size &&
                    y >= discard_y_pos && y < discard_y_pos + discard_btn_size) {
                    discard_hovered = true;
                }
            }
        }

        if (was_action_hovered != action_hovered || was_discard_hovered != discard_hovered) {
            set_dirty();
        }

        return false;
    }

    bool on_mouse_leave() override {
        if (action_hovered || discard_hovered) {
            action_hovered = false;
            discard_hovered = false;
            set_dirty();
        }
        return false;
    }

    bool on_mouse_down(float x, float y, int button) override {
        // Right-click: show context menu
        if (button == 1) {
            if (on_context_menu) {
                // Convert to screen coordinates
                POINT pt = { static_cast<LONG>(rect.x + x), static_cast<LONG>(rect.y + y) };
                ClientToScreen(g_main_window, &pt);
                on_context_menu(this, static_cast<float>(pt.x), static_cast<float>(pt.y), user_data);
            }
            return true;
        }

        // Left-click handling
        if (action_hovered) {
            if (on_action) {
                on_action(this, user_data);
            }
            return true;
        }

        // Check discard button click
        if (discard_hovered) {
            if (on_discard) {
                on_discard(this, user_data);
            }
            return true;
        }

        // Regular click - select file
        if (on_select) {
            on_select(this, user_data);
        }

        return true;
    }

    bool on_double_click(float x, float y, int button) override {
        (void)x; (void)y; (void)button;

        // Double-click toggles stage/unstage (same as action button)
        // Skip if action buttons are hidden (commit view mode)
        if (on_action && !hide_action_buttons) {
            on_action(this, user_data);
            return true;
        }
        return false;
    }

    // Set file data
    void set_file(const wchar_t* fname, const wchar_t* fpath, FileListItemStatus stat, int idx, bool staged,
                  const wchar_t* opath = nullptr, uint8_t sim = 0) {
        if (fname) wcscpy_s(filename, fname);
        if (fpath) wcscpy_s(full_path, fpath);
        if (opath) wcscpy_s(old_path, opath);
        else old_path[0] = L'\0';
        status = stat;
        similarity = sim;
        file_index = idx;
        is_staged = staged;
        set_dirty();
    }

    void set_selected(bool sel) {
        if (selected != sel) {
            selected = sel;
            set_dirty();
        }
    }
};

// ============================================================================
// FileList Widget
// ============================================================================
// A virtualized, scrollable list of file items.
// Uses ScrollContainer for scroll behavior but implements virtualization
// to only render visible items for performance with large file lists.

struct FileList : Widget {
    // Section identity
    bool is_staged_section = false;
    bool collapsed = false;
    bool external_scroll = false;  // When true, parent ScrollContainer handles scrolling
    bool hide_action_buttons = false; // Hide stage/unstage/discard buttons (for commit view)

    // Viewport bounds (set by parent when external_scroll = true)
    float viewport_top = 0.0f;     // Absolute Y of visible area top
    float viewport_bottom = 0.0f;  // Absolute Y of visible area bottom

    // Item storage (we maintain a list of items that can be reused).
    // Raised from 64 → 4096 because real repos routinely have hundreds of
    // changed files (rebases, large refactors). The cap is still bounded
    // so the static array doesn't grow unbounded.
    static constexpr size_t MAX_FILE_ITEMS = 4096;
    FileListItem* items[MAX_FILE_ITEMS] = {};
    size_t item_count = 0;

    // Scroll state
    float scroll_y = 0.0f;
    float scroll_speed = DiffViewer::SCROLL_SPEED;

    // Scrollbar
    float scrollbar_width = Sidebar::SCROLLBAR_WIDTH;
    float scrollbar_min_thumb = Sidebar::SCROLLBAR_MIN_THUMB;
    float scrollbar_button_size = Sidebar::SCROLLBAR_BUTTON_SIZE;
    float scrollbar_thumb_margin = Sidebar::SCROLLBAR_THUMB_MARGIN;
    bool scrollbar_dragging = false;
    float drag_start_y = 0.0f;
    float drag_start_offset = 0.0f;

    // Scrollbar hover state
    enum class ScrollbarHover { None, UpButton, DownButton, Thumb, Track };
    ScrollbarHover scrollbar_hover = ScrollbarHover::None;

    // Cached geometry
    float thumb_top = 0.0f;
    float thumb_bottom = 0.0f;
    float track_top = 0.0f;
    float track_bottom = 0.0f;

    // Selection
    int selected_index = -1;

    // Callbacks
    void (*on_file_select)(FileList* list, int index, void* user_data) = nullptr;
    void (*on_file_action)(FileList* list, int index, void* user_data) = nullptr;
    void (*on_file_discard)(FileList* list, int index, void* user_data) = nullptr;
    void (*on_file_double_click)(FileList* list, int index, void* user_data) = nullptr;
    void (*on_file_context_menu)(FileList* list, int index, float screen_x, float screen_y, void* user_data) = nullptr;
    void* user_data = nullptr;

    // Callback for requesting scroll position change (handled by parent when external_scroll = true)
    void (*on_scroll_request)(FileList* list, float scroll_y, void* user_data) = nullptr;
    void* scroll_request_user_data = nullptr;

    FileList() {
        flags |= WidgetFlags::ClipChildren;
        flags |= WidgetFlags::CapturesMouse;
        flags |= WidgetFlags::Focusable;
    }

    float get_content_height() const {
        if (collapsed) return 0.0f;
        return item_count * Sidebar::FILE_ITEM_HEIGHT_V2;
    }

    void measure(const LayoutConstraints& constraints) override {
        if (external_scroll) {
            // When using external scroll, report full content height
            preferred_height = get_content_height();
        } else if (preferred_height <= 0.0f) {
            // Use preferred_height if set externally (for layout integration)
            preferred_height = constraints.max_height;
        }
        rect.width = constraints.max_width;
        rect.height = preferred_height;
    }

    void layout() override {
        if (collapsed) {
            scroll_y = 0.0f;
            return;
        }

        float viewport_height = rect.height;
        float content_height = get_content_height();

        // When external scroll is enabled, parent handles scrolling
        float effective_scroll = external_scroll ? 0.0f : scroll_y;
        float item_width = external_scroll ? rect.width : (rect.width - scrollbar_width);

        if (!external_scroll) {
            // Clamp scroll (only when handling our own scroll)
            float max_scroll = fmaxf(0.0f, content_height - viewport_height);
            if (scroll_y > max_scroll) scroll_y = max_scroll;
            if (scroll_y < 0) scroll_y = 0;
        }

        // Position items
        float y = rect.y - effective_scroll;
        for (size_t i = 0; i < item_count; i++) {
            if (items[i]) {
                items[i]->rect.x = rect.x;
                items[i]->rect.y = y;
                items[i]->rect.width = item_width;
                items[i]->rect.height = Sidebar::FILE_ITEM_HEIGHT_V2;
                y += Sidebar::FILE_ITEM_HEIGHT_V2;
            }
        }

        if (!external_scroll) {
            update_scrollbar_geometry();
        }
    }

    void update_scrollbar_geometry() {
        float viewport_height = rect.height;
        float content_height = get_content_height();

        track_top = rect.y + scrollbar_button_size;
        track_bottom = rect.y + rect.height - scrollbar_button_size;
        float track_height = track_bottom - track_top;

        float visible_ratio = viewport_height / fmaxf(content_height, 1.0f);
        float thumb_height = fmaxf(track_height * fminf(visible_ratio, 1.0f), scrollbar_min_thumb);

        float max_scroll = fmaxf(0.0f, content_height - viewport_height);
        float scroll_ratio = max_scroll > 0 ? scroll_y / max_scroll : 0.0f;
        float available_track = track_height - thumb_height;

        thumb_top = track_top + scroll_ratio * available_track;
        thumb_bottom = thumb_top + thumb_height;
    }

    void render(RenderContext& ctx) override {
        if (collapsed) return;

        // Note: Focus ring is drawn on selected item, not the list itself
        // Set show_keyboard_focus flag on selected item when we have keyboard focus
        bool has_kb_focus = static_cast<bool>(flags & WidgetFlags::KeyboardFocused);
        for (size_t i = 0; i < item_count; i++) {
            if (items[i]) {
                items[i]->show_keyboard_focus = has_kb_focus && items[i]->selected;
            }
        }

        float viewport_height = rect.height;
        float content_height = get_content_height();

        // When using external scroll, parent handles clipping and scrollbar
        if (external_scroll) {
            // Virtualization: only render items within parent's visible viewport
            float item_height = Sidebar::FILE_ITEM_HEIGHT_V2;

            for (size_t i = 0; i < item_count; i++) {
                if (!items[i]) continue;

                float item_top = items[i]->rect.y;
                float item_bottom = item_top + item_height;

                // Skip if item is fully above visible area
                if (item_bottom < viewport_top) continue;

                // Stop if item is fully below visible area (items are in order)
                if (item_top > viewport_bottom) break;

                items[i]->render(ctx);
            }
            return;
        }

        float viewport_width = rect.width - (content_height > viewport_height ? scrollbar_width : 0.0f);

        // Clip to viewport (excluding scrollbar)
        D2D1_RECT_F clip_rect = D2D1::RectF(rect.x, rect.y, rect.x + viewport_width, rect.y + viewport_height);
        ctx.push_clip(clip_rect);

        // Render only visible items (virtualization)
        float item_height = Sidebar::FILE_ITEM_HEIGHT_V2;
        int first_visible = static_cast<int>(scroll_y / item_height);
        int last_visible = static_cast<int>((scroll_y + viewport_height) / item_height) + 1;

        for (int i = first_visible; i <= last_visible && i < static_cast<int>(item_count); i++) {
            if (i < 0) continue;
            if (items[i]) {
                // Skip if fully outside viewport
                if (items[i]->rect.y + items[i]->rect.height < rect.y) continue;
                if (items[i]->rect.y > rect.y + viewport_height) continue;

                items[i]->render(ctx);
            }
        }

        ctx.pop_clip();

        // Render scrollbar if needed
        if (content_height > viewport_height) {
            render_scrollbar(ctx);
        }
    }

    void render_scrollbar(RenderContext& ctx) {
        float sb_x = rect.x + rect.width - scrollbar_width;

        // Track background
        D2D1_RECT_F track_rect = D2D1::RectF(sb_x, rect.y, sb_x + scrollbar_width, rect.y + rect.height);
        ctx.fill_rect(track_rect, Theme::BG_SECONDARY);

        // Up button
        D2D1_RECT_F up_rect = D2D1::RectF(sb_x, rect.y, sb_x + scrollbar_width, rect.y + scrollbar_button_size);
        if (scrollbar_hover == ScrollbarHover::UpButton) {
            ctx.fill_rect(up_rect, Theme::BG_TERTIARY);
        }
        draw_scrollbar_arrow(ctx, sb_x + scrollbar_width / 2.0f, rect.y + scrollbar_button_size / 2.0f, true);

        // Down button
        D2D1_RECT_F down_rect = D2D1::RectF(sb_x, rect.y + rect.height - scrollbar_button_size,
                                            sb_x + scrollbar_width, rect.y + rect.height);
        if (scrollbar_hover == ScrollbarHover::DownButton) {
            ctx.fill_rect(down_rect, Theme::BG_TERTIARY);
        }
        draw_scrollbar_arrow(ctx, sb_x + scrollbar_width / 2.0f, rect.y + rect.height - scrollbar_button_size / 2.0f, false);

        // Thumb
        D2D1_RECT_F thumb_rect = D2D1::RectF(
            sb_x + scrollbar_thumb_margin, thumb_top,
            sb_x + scrollbar_width - scrollbar_thumb_margin, thumb_bottom);
        uint32_t thumb_color = (scrollbar_hover == ScrollbarHover::Thumb || scrollbar_dragging)
                              ? Theme::TEXT_MUTED : Theme::BG_HOVER;
        ctx.fill_rounded_rect(thumb_rect, 3.0f, thumb_color);
    }

    void draw_scrollbar_arrow(RenderContext& ctx, float cx, float cy, bool up) {
        ctx.brush->SetColor(color_from_argb(Theme::TEXT_MUTED));
        float size = 4.0f;
        if (up) {
            ctx.target->DrawLine(D2D1::Point2F(cx, cy - size), D2D1::Point2F(cx - size, cy + size / 2.0f), ctx.brush, 1.0f);
            ctx.target->DrawLine(D2D1::Point2F(cx, cy - size), D2D1::Point2F(cx + size, cy + size / 2.0f), ctx.brush, 1.0f);
        } else {
            ctx.target->DrawLine(D2D1::Point2F(cx, cy + size), D2D1::Point2F(cx - size, cy - size / 2.0f), ctx.brush, 1.0f);
            ctx.target->DrawLine(D2D1::Point2F(cx, cy + size), D2D1::Point2F(cx + size, cy - size / 2.0f), ctx.brush, 1.0f);
        }
    }

    bool on_mouse_wheel(float x, float y, float delta) override {
        (void)x; (void)y;
        if (collapsed) return false;
        if (external_scroll) return false;  // Let parent handle scrolling

        float viewport_height = rect.height;
        float content_height = get_content_height();
        float max_scroll = fmaxf(0.0f, content_height - viewport_height);

        scroll_y -= delta * scroll_speed;
        scroll_y = fminf(fmaxf(scroll_y, 0.0f), max_scroll);

        layout();
        set_dirty();
        return true;
    }

    // FileListItem widgets live in items[] only (not the parent/child tree), so
    // EventDispatcher hit-tests this list as a leaf. Route double-click the same
    // way as single-click: map Y → index and forward to the item.
    bool on_double_click(float x, float y, int button) override {
        if (collapsed) return false;
        if (button != 0) return false;  // left button only

        float item_height = Sidebar::FILE_ITEM_HEIGHT_V2;
        float effective_scroll = external_scroll ? 0.0f : scroll_y;
        int clicked_index = static_cast<int>((y + effective_scroll) / item_height);

        if (clicked_index >= 0 && clicked_index < static_cast<int>(item_count)) {
            FileListItem* item = items[clicked_index];
            if (item) {
                float item_local_y = item->rect.y - rect.y;
                return item->on_double_click(x, y - item_local_y, button);
            }
        }
        return false;
    }

    bool on_mouse_down(float x, float y, int button) override {
        float content_height = get_content_height();
        float viewport_height = rect.height;

        // Check if in scrollbar area (skip when using external scroll)
        if (!external_scroll && content_height > viewport_height) {
            float sb_x = rect.width - scrollbar_width;
            if (x >= sb_x) {
                // Up button
                if (y < scrollbar_button_size) {
                    scroll_by_line(-1);
                    return true;
                }
                // Down button
                if (y > rect.height - scrollbar_button_size) {
                    scroll_by_line(1);
                    return true;
                }
                // Thumb drag
                float rel_thumb_top = thumb_top - rect.y;
                float rel_thumb_bottom = thumb_bottom - rect.y;
                if (y >= rel_thumb_top && y < rel_thumb_bottom) {
                    scrollbar_dragging = true;
                    // Store ABSOLUTE position (captured mode receives absolute coords)
                    drag_start_y = rect.y + y;
                    drag_start_offset = scroll_y;
                    return true;
                }
                // Track click - page up/down
                if (y < rel_thumb_top) {
                    scroll_by_page(-1);
                } else {
                    scroll_by_page(1);
                }
                return true;
            }
        }

        // Check which item was clicked
        float item_height = Sidebar::FILE_ITEM_HEIGHT_V2;
        // When using external scroll, y is already relative to list position
        float effective_scroll = external_scroll ? 0.0f : scroll_y;
        int clicked_index = static_cast<int>((y + effective_scroll) / item_height);

        if (clicked_index >= 0 && clicked_index < static_cast<int>(item_count)) {
            FileListItem* item = items[clicked_index];
            if (item) {
                // Calculate item's Y position relative to FileList
                // Note: item->rect.y already has scroll offset from layout(), so don't subtract again
                float item_local_y = item->rect.y - rect.y;
                // Pass item-relative mouse coordinates
                item->on_mouse_down(x, y - item_local_y, button);
            }
        }

        return true;
    }

    bool on_mouse_up(float x, float y, int button) override {
        (void)x; (void)y; (void)button;
        if (scrollbar_dragging) {
            scrollbar_dragging = false;
            return true;  // We were handling scrollbar drag
        }
        return false;  // Not handling - let other widgets process
    }

    bool on_mouse_move(float x, float y) override {
        // Handle scrollbar drag (only when not using external scroll)
        // When captured (during drag), y is ABSOLUTE; drag_start_y stored as absolute
        if (!external_scroll && scrollbar_dragging) {
            float delta_y = y - drag_start_y;
            float track_height = track_bottom - track_top;
            float thumb_height = thumb_bottom - thumb_top;
            float available_track = track_height - thumb_height;

            if (available_track > 0) {
                float viewport_height = rect.height;
                float content_height = get_content_height();
                float max_scroll = fmaxf(0.0f, content_height - viewport_height);
                float scroll_delta = (delta_y / available_track) * max_scroll;

                scroll_y = fminf(fmaxf(drag_start_offset + scroll_delta, 0.0f), max_scroll);
                layout();
                set_dirty();
            }
            return true;
        }

        // Update scrollbar hover state (skip when using external scroll)
        float content_height = get_content_height();
        float viewport_height = rect.height;

        ScrollbarHover old_hover = scrollbar_hover;
        scrollbar_hover = ScrollbarHover::None;

        if (!external_scroll && content_height > viewport_height) {
            float sb_x = rect.width - scrollbar_width;
            if (x >= sb_x) {
                if (y < scrollbar_button_size) {
                    scrollbar_hover = ScrollbarHover::UpButton;
                } else if (y > rect.height - scrollbar_button_size) {
                    scrollbar_hover = ScrollbarHover::DownButton;
                } else {
                    float rel_thumb_top = thumb_top - rect.y;
                    float rel_thumb_bottom = thumb_bottom - rect.y;
                    if (y >= rel_thumb_top && y < rel_thumb_bottom) {
                        scrollbar_hover = ScrollbarHover::Thumb;
                    } else {
                        scrollbar_hover = ScrollbarHover::Track;
                    }
                }
            }
        }

        if (old_hover != scrollbar_hover) {
            set_dirty();
        }

        // Update item hover states
        float item_height_val = Sidebar::FILE_ITEM_HEIGHT_V2;
        // When using external scroll, y is already relative to list position
        float effective_scroll = external_scroll ? 0.0f : scroll_y;
        int hovered_index = static_cast<int>((y + effective_scroll) / item_height_val);
        bool hover_changed = false;

        // Clear all hover states first
        for (size_t i = 0; i < item_count; i++) {
            if (items[i] && (items[i]->flags & WidgetFlags::Hovered)) {
                items[i]->flags &= ~WidgetFlags::Hovered;
                items[i]->on_mouse_leave();
                hover_changed = true;
            }
        }

        // Set hover on current item (skip scrollbar check when using external scroll)
        bool not_over_scrollbar = external_scroll || scrollbar_hover == ScrollbarHover::None;
        if (hovered_index >= 0 && hovered_index < static_cast<int>(item_count) && not_over_scrollbar) {
            FileListItem* item = items[hovered_index];
            if (item) {
                item->flags |= WidgetFlags::Hovered;
                // Calculate item's Y position relative to FileList
                // Note: item->rect.y already has scroll offset from layout(), so don't subtract again
                float item_local_y = item->rect.y - rect.y;
                // Pass item-relative mouse coordinates
                item->on_mouse_move(x, y - item_local_y);
                hover_changed = true;
            }
        }

        // Trigger redraw if hover state changed
        if (hover_changed) {
            set_dirty();
        }

        return false;
    }

    bool on_mouse_leave() override {
        // Clear all hover states
        for (size_t i = 0; i < item_count; i++) {
            if (items[i] && (items[i]->flags & WidgetFlags::Hovered)) {
                items[i]->flags &= ~WidgetFlags::Hovered;
                items[i]->on_mouse_leave();
            }
        }
        if (scrollbar_hover != ScrollbarHover::None) {
            scrollbar_hover = ScrollbarHover::None;
            set_dirty();
        }
        return false;
    }

    void scroll_by_line(int direction) {
        float viewport_height = rect.height;
        float content_height = get_content_height();
        float max_scroll = fmaxf(0.0f, content_height - viewport_height);

        scroll_y += direction * Sidebar::FILE_ITEM_HEIGHT_V2;
        scroll_y = fminf(fmaxf(scroll_y, 0.0f), max_scroll);

        layout();
        set_dirty();
    }

    void scroll_by_page(int direction) {
        float viewport_height = rect.height;
        float content_height = get_content_height();
        float max_scroll = fmaxf(0.0f, content_height - viewport_height);

        scroll_y += direction * (viewport_height - Sidebar::FILE_ITEM_HEIGHT_V2);
        scroll_y = fminf(fmaxf(scroll_y, 0.0f), max_scroll);

        layout();
        set_dirty();
    }

    void ensure_visible(int index) {
        if (index < 0 || index >= static_cast<int>(item_count)) return;

        float item_height = Sidebar::FILE_ITEM_HEIGHT_V2;
        float item_top = index * item_height;
        float item_bottom = item_top + item_height;

        if (external_scroll) {
            // When using external scroll, request parent to scroll
            // Item positions are relative to the FileList's rect.y
            float list_item_top = rect.y + item_top;
            float list_item_bottom = rect.y + item_bottom;

            float new_scroll_offset = -1.0f;  // -1 means no change needed
            if (list_item_top < viewport_top) {
                // Item is above viewport - scroll up
                new_scroll_offset = item_top;
            } else if (list_item_bottom > viewport_bottom) {
                // Item is below viewport - scroll down
                float viewport_height = viewport_bottom - viewport_top;
                new_scroll_offset = item_bottom - viewport_height;
            }

            if (new_scroll_offset >= 0.0f && on_scroll_request) {
                on_scroll_request(this, new_scroll_offset, scroll_request_user_data);
            }
        } else {
            // Internal scrolling
            float viewport_height = rect.height;
            if (item_top < scroll_y) {
                scroll_y = item_top;
            } else if (item_bottom > scroll_y + viewport_height) {
                scroll_y = item_bottom - viewport_height;
            }
            layout();
        }
        set_dirty();
    }

    // Clear all items
    void clear() {
        item_count = 0;
        selected_index = -1;
        scroll_y = 0.0f;
        for (size_t i = 0; i < MAX_FILE_ITEMS; i++) {
            items[i] = nullptr;
        }
        set_dirty();
    }

    // Add an item
    FileListItem* add_item() {
        if (item_count >= MAX_FILE_ITEMS) return nullptr;

        FileListItem* item = g_widget_arena.create<FileListItem>();
        if (!item) return nullptr;

        item->parent_list = this;
        item->hide_action_buttons = hide_action_buttons;  // Propagate from list
        items[item_count++] = item;

        // Set up item callbacks to forward to list
        item->user_data = this;
        item->on_select = [](FileListItem* it, void* ud) {
            FileList* list = static_cast<FileList*>(ud);
            list->handle_item_select(it);
        };
        item->on_action = [](FileListItem* it, void* ud) {
            FileList* list = static_cast<FileList*>(ud);
            list->handle_item_action(it);
        };
        item->on_discard = [](FileListItem* it, void* ud) {
            FileList* list = static_cast<FileList*>(ud);
            list->handle_item_discard(it);
        };
        item->on_context_menu = [](FileListItem* it, float sx, float sy, void* ud) {
            FileList* list = static_cast<FileList*>(ud);
            list->handle_item_context_menu(it, sx, sy);
        };

        return item;
    }

    void handle_item_select(FileListItem* item) {
        // Clear previous selection
        if (selected_index >= 0 && selected_index < static_cast<int>(item_count)) {
            if (items[selected_index]) {
                items[selected_index]->set_selected(false);
            }
        }

        // Set new selection
        selected_index = item->file_index;
        item->set_selected(true);

        if (on_file_select) {
            on_file_select(this, item->file_index, user_data);
        }
    }

    void handle_item_action(FileListItem* item) {
        if (on_file_action) {
            on_file_action(this, item->file_index, user_data);
        }
    }

    void handle_item_discard(FileListItem* item) {
        if (on_file_discard) {
            on_file_discard(this, item->file_index, user_data);
        }
    }

    void handle_item_context_menu(FileListItem* item, float screen_x, float screen_y) {
        if (on_file_context_menu) {
            on_file_context_menu(this, item->file_index, screen_x, screen_y, user_data);
        }
    }

    void set_selected(int index) {
        // Clear previous selection
        if (selected_index >= 0 && selected_index < static_cast<int>(item_count)) {
            if (items[selected_index]) {
                items[selected_index]->set_selected(false);
            }
        }

        selected_index = index;

        // Set new selection
        if (index >= 0 && index < static_cast<int>(item_count)) {
            if (items[index]) {
                items[index]->set_selected(true);
            }
        }

        set_dirty();
    }

    void on_viewport_changed(float vp_top, float vp_bottom) override {
        if (external_scroll) {
            viewport_top = vp_top;
            viewport_bottom = vp_bottom;
        }
    }

    void set_collapsed(bool state) {
        if (collapsed != state) {
            collapsed = state;
            if (collapsed) {
                scroll_y = 0.0f;
            }
            set_dirty();
        }
    }

    bool on_key_down(int vk, bool ctrl, bool shift, bool alt) override {
        (void)ctrl; (void)shift; (void)alt;
        if (collapsed || item_count == 0) return false;

        int new_index = selected_index;

        if (vk == VK_UP) {
            if (selected_index <= 0) {
                new_index = 0;
            } else {
                new_index = selected_index - 1;
            }
        } else if (vk == VK_DOWN) {
            if (selected_index < 0) {
                new_index = 0;
            } else if (selected_index < static_cast<int>(item_count) - 1) {
                new_index = selected_index + 1;
            }
        } else if (vk == VK_HOME) {
            new_index = 0;
        } else if (vk == VK_END) {
            new_index = static_cast<int>(item_count) - 1;
        } else if (vk == VK_PRIOR) {  // Page Up
            int page_items = static_cast<int>(rect.height / Sidebar::FILE_ITEM_HEIGHT_V2);
            new_index = (selected_index > page_items) ? selected_index - page_items : 0;
        } else if (vk == VK_NEXT) {  // Page Down
            int page_items = static_cast<int>(rect.height / Sidebar::FILE_ITEM_HEIGHT_V2);
            int max_idx = static_cast<int>(item_count) - 1;
            new_index = (selected_index + page_items < max_idx) ? selected_index + page_items : max_idx;
        } else if (vk == VK_RETURN || vk == VK_SPACE) {
            // Activate the action (stage/unstage)
            if (selected_index >= 0 && selected_index < static_cast<int>(item_count)) {
                if (on_file_action) {
                    on_file_action(this, selected_index, user_data);
                }
                return true;
            }
            return false;
        } else {
            return false;
        }

        if (new_index != selected_index) {
            set_selected(new_index);
            ensure_visible(new_index);
            if (on_file_select) {
                on_file_select(this, new_index, user_data);
            }
        }
        return true;
    }
};

// ============================================================================
// BranchTreeItem Widget
// ============================================================================
// Represents a single row in the flattened branch tree (folder or leaf branch).

struct BranchTree;  // Forward declaration

struct BranchTreeItem : Widget {
    // Data binding
    int node_index = -1;            // Index into BranchTreeState::nodes[]

    // Cached display data
    char name[64] = {};
    int depth = 0;
    bool is_folder = false;
    bool is_expanded = false;       // Only meaningful for folders
    bool is_current_branch = false; // True if this is the current branch
    int git_ref_index = -1;         // For checkout on double-click

    // Cached text layout (expensive to create per frame)
    wchar_t name_wide[256] = {};
    IDWriteTextLayout* cached_layout = nullptr;
    float cached_layout_width = 0.0f;

    // Keyboard focus state (set by parent BranchTree before rendering)
    bool show_keyboard_focus = false;

    // Visual constants
    static constexpr float ITEM_HEIGHT = Sidebar::BRANCH_ITEM_HEIGHT;  // 24.0f
    static constexpr float INDENT_PER_LEVEL = Sidebar::BRANCH_INDENT;  // 16.0f
    static constexpr float CHEVRON_OFFSET_X = 2.0f;
    static constexpr float CHEVRON_HALF_SIZE = 5.0f;
    static constexpr float CHEVRON_VERT_OFFSET = 3.0f;
    static constexpr float ICON_OFFSET_X = 4.0f;
    static constexpr float ICON_VERT_OFFSET = 3.0f;
    static constexpr float FOLDER_ICON_WIDTH = 16.0f;
    static constexpr float BRANCH_ICON_WIDTH = 18.0f;

    // Parent tree (for callbacks)
    BranchTree* parent_tree = nullptr;

    BranchTreeItem() {
        preferred_height = ITEM_HEIGHT;
        height_mode = SizeMode::Fixed;
    }

    ~BranchTreeItem() {
        release_cached_layout();
    }

    void release_cached_layout() {
        if (cached_layout) {
            cached_layout->Release();
            cached_layout = nullptr;
        }
        cached_layout_width = 0.0f;
    }

    void update_cached_layout(float available_width) {
        // Convert name to wide char if not already done
        if (name_wide[0] == L'\0' && name[0] != '\0') {
            MultiByteToWideChar(CP_UTF8, 0, name, -1, name_wide, 256);
        }

        // Recreate layout if width changed significantly or layout doesn't exist
        // Use epsilon to avoid thrashing on tiny float differences
        constexpr float WIDTH_EPSILON = 0.5f;
        bool width_changed = (cached_layout_width - available_width > WIDTH_EPSILON) ||
                             (available_width - cached_layout_width > WIDTH_EPSILON);
        if (!cached_layout || width_changed) {
            release_cached_layout();
            cached_layout = file_list_create_text_layout_ellipsis(
                name_wide,
                g_text_format_body,
                available_width,
                ITEM_HEIGHT
            );
            cached_layout_width = available_width;
        }
    }

    void invalidate_cache() {
        release_cached_layout();
        name_wide[0] = L'\0';  // Force re-conversion on next update
    }

    void measure(const LayoutConstraints& constraints) override {
        preferred_height = ITEM_HEIGHT;
        preferred_width = constraints.max_width;
        rect.width = preferred_width;
        rect.height = preferred_height;
    }

    void render(RenderContext& ctx) override {
        float height = rect.height;
        D2D1_RECT_F bg_rect = D2D1::RectF(
            rect.x, rect.y,
            rect.x + rect.width, rect.y + height
        );

        // Background (keyboard selection, current branch highlight, or hover)
        // show_keyboard_focus is set by parent BranchTree before rendering
        if (show_keyboard_focus) {
            // Keyboard selection highlight with focus ring
            D2D1_COLOR_F sel_color = color_from_argb(Theme::ACCENT);
            sel_color.a = 0.12f;
            ctx.brush->SetColor(sel_color);
            ctx.target->FillRectangle(bg_rect, ctx.brush);

            // Left border for selection
            D2D1_RECT_F border_rect = D2D1::RectF(rect.x, rect.y, rect.x + 2.0f, rect.y + height);
            ctx.fill_rect(border_rect, Theme::SELECTION_BORDER);

            // Focus ring
            D2D1_RECT_F focus_rect = D2D1::RectF(
                rect.x + 2.0f, rect.y + 1.0f,
                rect.x + rect.width - 2.0f, rect.y + height - 1.0f);
            ctx.brush->SetColor(color_from_argb(Theme::ACCENT));
            D2D1_ROUNDED_RECT rr = { focus_rect, 3.0f, 3.0f };
            ctx.target->DrawRoundedRectangle(rr, ctx.brush, 2.0f);
        } else if (is_current_branch && !is_folder) {
            // Accent highlight + left border for current branch
            D2D1_COLOR_F sel_color = color_from_argb(Theme::ACCENT);
            sel_color.a = 0.12f;
            ctx.brush->SetColor(sel_color);
            ctx.target->FillRectangle(bg_rect, ctx.brush);

            // 2px left border in accent color
            D2D1_RECT_F border_rect = D2D1::RectF(rect.x, rect.y, rect.x + 2.0f, rect.y + height);
            ctx.fill_rect(border_rect, Theme::ACCENT);
        } else if (flags & WidgetFlags::Hovered) {
            ctx.fill_rect(bg_rect, Theme::BG_HOVER);
        }

        float x = rect.x + Theme::PADDING + depth * INDENT_PER_LEVEL;

        if (is_folder) {
            render_folder_chevron(ctx, x, rect.y + height / 2.0f);
            x += FOLDER_ICON_WIDTH;
        } else {
            render_branch_icon(ctx, x, rect.y + height / 2.0f);
            x += BRANCH_ICON_WIDTH;
        }

        // Use cached text layout (update if width changed)
        float text_width = rect.x + rect.width - x - Theme::PADDING;
        update_cached_layout(text_width);

        if (cached_layout) {
            bool is_leaf_current = !is_folder && is_current_branch;
            uint32_t text_color = is_leaf_current ? Theme::ACCENT : Theme::TEXT_SECONDARY;
            ctx.brush->SetColor(color_from_argb(text_color));
            ctx.target->DrawTextLayout(
                D2D1::Point2F(x, rect.y),
                cached_layout,
                ctx.brush
            );
        }
    }

    bool on_mouse_enter() override {
        flags |= WidgetFlags::Hovered;
        set_dirty();
        return true;
    }

    bool on_mouse_leave() override {
        flags &= ~WidgetFlags::Hovered;
        set_dirty();
        return true;
    }

    bool on_mouse_down(float x, float y, int button) override;
    bool on_double_click(float x, float y, int button) override;

private:
    void render_folder_chevron(RenderContext& ctx, float x, float y) {
        ctx.brush->SetColor(color_from_argb(Theme::TEXT_SECONDARY));
        float chevron_x = x + CHEVRON_OFFSET_X;

        if (is_expanded) {
            // Down chevron (▼)
            ctx.target->DrawLine(
                D2D1::Point2F(chevron_x, y - CHEVRON_VERT_OFFSET),
                D2D1::Point2F(chevron_x + CHEVRON_HALF_SIZE, y + 2.0f),
                ctx.brush, 2.0f
            );
            ctx.target->DrawLine(
                D2D1::Point2F(chevron_x + CHEVRON_HALF_SIZE, y + 2.0f),
                D2D1::Point2F(chevron_x + CHEVRON_HALF_SIZE * 2.0f, y - CHEVRON_VERT_OFFSET),
                ctx.brush, 2.0f
            );
        } else {
            // Right chevron (▶)
            ctx.target->DrawLine(
                D2D1::Point2F(chevron_x, y - CHEVRON_HALF_SIZE),
                D2D1::Point2F(chevron_x + CHEVRON_HALF_SIZE, y),
                ctx.brush, 2.0f
            );
            ctx.target->DrawLine(
                D2D1::Point2F(chevron_x + CHEVRON_HALF_SIZE, y),
                D2D1::Point2F(chevron_x, y + CHEVRON_HALF_SIZE),
                ctx.brush, 2.0f
            );
        }
    }

    void render_branch_icon(RenderContext& ctx, float x, float y) {
        uint32_t color = is_current_branch ? Theme::ACCENT : Theme::TEXT_MUTED;
        ctx.brush->SetColor(color_from_argb(color));

        float icon_x = x + ICON_OFFSET_X;

        // Y-shape: two lines converging, then one line down
        ctx.target->DrawLine(
            D2D1::Point2F(icon_x, y - ICON_VERT_OFFSET),
            D2D1::Point2F(icon_x + 2.0f, y),
            ctx.brush, 1.0f
        );
        ctx.target->DrawLine(
            D2D1::Point2F(icon_x + 4.0f, y - ICON_VERT_OFFSET),
            D2D1::Point2F(icon_x + 2.0f, y),
            ctx.brush, 1.0f
        );
        ctx.target->DrawLine(
            D2D1::Point2F(icon_x + 2.0f, y),
            D2D1::Point2F(icon_x + 2.0f, y + ICON_VERT_OFFSET),
            ctx.brush, 1.0f
        );
    }
};

// ============================================================================
// BranchTree Widget
// ============================================================================
// Container widget managing the list of BranchTreeItem widgets.
// Uses external scroll (parent provides viewport/scrollbar).

struct BranchTree : Widget {
    // Items (flattened tree).
    // Raised from 256 → 4096 to handle repos with many branches (Linux kernel,
    // gitlab, fork networks). The cap remains so a runaway clone of a fork-
    // bomb repo can't blow our memory.
    static constexpr size_t MAX_BRANCH_ITEMS = 4096;
    BranchTreeItem* items[MAX_BRANCH_ITEMS] = {};
    size_t item_count = 0;

    // External scroll support (like FileList)
    bool external_scroll = true;
    float viewport_top = 0.0f;      // Set by parent for virtualization
    float viewport_bottom = 0.0f;

    // Collapsed state (section can be collapsed by SectionHeader)
    bool collapsed = false;

    // Selection
    int hovered_index = -1;         // Currently hovered item
    int current_branch_flattened_index = -1; // For highlighting

    // Double-click detection
    DWORD last_click_time = 0;
    int last_click_index = -1;
    static constexpr DWORD DOUBLE_CLICK_TIME = 500;  // ms

    // Callbacks
    void (*on_folder_toggle)(BranchTree* tree, int node_index, void* user_data) = nullptr;
    void (*on_branch_checkout)(BranchTree* tree, int git_ref_index, void* user_data) = nullptr;
    void (*on_hover_change)(BranchTree* tree, int node_index, void* user_data) = nullptr;
    void (*on_branch_context_menu)(BranchTree* tree, int git_ref_index, int node_index,
                                    float screen_x, float screen_y, void* user_data) = nullptr;
    void* user_data = nullptr;

    // Selection for keyboard navigation
    int selected_index = -1;

    // Callback for requesting scroll position change (handled by parent when external_scroll = true)
    void (*on_scroll_request)(BranchTree* tree, float scroll_y, void* user_data) = nullptr;
    void* scroll_request_user_data = nullptr;

    BranchTree() {
        flags |= WidgetFlags::ClipChildren;
        flags |= WidgetFlags::CapturesMouse;
        flags |= WidgetFlags::RendersOwnChildren;  // We handle child rendering for virtualization
        flags |= WidgetFlags::Focusable;
    }

    float get_content_height() const {
        if (collapsed) return 0.0f;
        return item_count * Sidebar::BRANCH_ITEM_HEIGHT;
    }

    void measure(const LayoutConstraints& constraints) override {
        if (external_scroll) {
            // When using external scroll, report full content height
            preferred_height = get_content_height();
        } else if (preferred_height <= 0.0f) {
            preferred_height = constraints.max_height;
        }
        rect.width = constraints.max_width;
        rect.height = preferred_height;
    }

    void layout() override {
        if (collapsed) return;

        // Position items sequentially
        float y = rect.y;
        float item_width = rect.width;

        for (size_t i = 0; i < item_count; i++) {
            if (items[i]) {
                items[i]->rect.x = rect.x;
                items[i]->rect.y = y;
                items[i]->rect.width = item_width;
                items[i]->rect.height = Sidebar::BRANCH_ITEM_HEIGHT;
                y += Sidebar::BRANCH_ITEM_HEIGHT;
            }
        }
    }

    void render(RenderContext& ctx) override {
        if (collapsed) return;

        // Set show_keyboard_focus flag on selected item when we have keyboard focus
        bool has_kb_focus = static_cast<bool>(flags & WidgetFlags::KeyboardFocused);
        for (size_t i = 0; i < item_count; i++) {
            if (items[i]) {
                items[i]->show_keyboard_focus = has_kb_focus && (static_cast<int>(i) == selected_index);
            }
        }

        // Virtualized rendering: only items between viewport_top and viewport_bottom
        float item_height = Sidebar::BRANCH_ITEM_HEIGHT;

        for (size_t i = 0; i < item_count; i++) {
            if (!items[i]) continue;

            float item_top = items[i]->rect.y;
            float item_bottom = item_top + item_height;

            // Skip if item is fully above visible area
            if (item_bottom < viewport_top) continue;

            // Stop if item is fully below visible area
            if (item_top > viewport_bottom) break;

            items[i]->render(ctx);
        }
    }

    bool on_mouse_move(float x, float y) override {
        (void)x;

        int new_hovered = hit_test_item(y);

        if (new_hovered != hovered_index) {
            // Clear old hover
            if (hovered_index >= 0 && hovered_index < static_cast<int>(item_count) && items[hovered_index]) {
                items[hovered_index]->flags &= ~WidgetFlags::Hovered;
                items[hovered_index]->set_dirty();
            }

            hovered_index = new_hovered;

            // Set new hover
            if (hovered_index >= 0 && hovered_index < static_cast<int>(item_count) && items[hovered_index]) {
                items[hovered_index]->flags |= WidgetFlags::Hovered;
                items[hovered_index]->set_dirty();

                // Notify tooltip system
                if (on_hover_change) {
                    on_hover_change(this, items[hovered_index]->node_index, user_data);
                }
            }

            set_dirty();
        }

        return true;
    }

    bool on_mouse_down(float x, float y, int button) override {
        (void)x;

        int clicked_index = hit_test_item(y);
        if (clicked_index < 0 || clicked_index >= static_cast<int>(item_count) || !items[clicked_index]) {
            return false;
        }

        BranchTreeItem* item = items[clicked_index];

        // Right-click: show context menu (for branches only, not folders)
        if (button == 1) {
            if (!item->is_folder && on_branch_context_menu) {
                // Convert to screen coordinates
                POINT pt = { static_cast<LONG>(rect.x + x), static_cast<LONG>(rect.y + y) };
                ClientToScreen(g_main_window, &pt);
                on_branch_context_menu(this, item->git_ref_index, item->node_index,
                                       static_cast<float>(pt.x), static_cast<float>(pt.y), user_data);
            }
            return true;
        }

        if (button != 0) return false;  // Only handle left click for other logic

        DWORD now = GetTickCount();

        if (item->is_folder) {
            // Single click on folder: toggle expand/collapse
            if (on_folder_toggle) {
                on_folder_toggle(this, item->node_index, user_data);
            }
        } else {
            // Record click for selection / display. Double-click → checkout is
            // handled by on_double_click(); doing it here too would fire the
            // checkout twice when the platform dispatches both events.
            last_click_index = clicked_index;
            last_click_time = now;
        }

        return true;
    }

    bool on_double_click(float x, float y, int button) override {
        (void)x;
        if (button != 0) return false;  // Only handle left click

        int clicked_index = hit_test_item(y);
        if (clicked_index < 0 || clicked_index >= static_cast<int>(item_count) || !items[clicked_index]) {
            return false;
        }

        BranchTreeItem* item = items[clicked_index];

        if (!item->is_folder && on_branch_checkout && item->git_ref_index >= 0) {
            // Double-click on branch: checkout
            on_branch_checkout(this, item->git_ref_index, user_data);
            // Clear timing state since we handled it
            last_click_index = -1;
            last_click_time = 0;
            return true;
        }

        return false;
    }

    bool on_mouse_leave() override {
        // Clear all item hover states
        if (hovered_index >= 0 && hovered_index < static_cast<int>(item_count) && items[hovered_index]) {
            items[hovered_index]->flags &= ~WidgetFlags::Hovered;
            items[hovered_index]->set_dirty();
        }
        hovered_index = -1;
        set_dirty();
        return true;
    }

    void clear() {
        // Release cached layouts before clearing (arena doesn't call dtors).
        // Walk the full slot array, not just item_count: when the list
        // shrinks across rebuilds, items beyond the new item_count still
        // hold live IDWriteTextLayout COM refs from their previous binding.
        for (size_t i = 0; i < MAX_BRANCH_ITEMS; i++) {
            if (items[i]) {
                items[i]->release_cached_layout();
            }
        }
        // Don't deallocate items, just reset count (arena owns memory)
        item_count = 0;
        hovered_index = -1;
        current_branch_flattened_index = -1;
    }

    void set_collapsed(bool state) {
        if (collapsed != state) {
            collapsed = state;
            set_dirty();
        }
    }

    // Rebuild items from branch tree state
    void rebuild_from_state() {
        clear();

        BranchTreeState* state = get_branch_tree_state();
        int current_branch_idx = get_current_branch_index();
        if (!state) return;

        current_branch_flattened_index = -1;

        for (size_t i = 0; i < state->flattened_count && i < MAX_BRANCH_ITEMS; i++) {
            int node_idx = state->flattened_indices[i];
            BranchTreeNode* node = &state->nodes[node_idx];

            // Create or reuse item
            if (!items[i]) {
                items[i] = g_widget_arena.create<BranchTreeItem>();
                if (!items[i]) continue;  // Allocation failed
                widget_add_child(this, items[i]);
            }

            BranchTreeItem* item = items[i];

            // Invalidate cache only if name changed (expensive operation)
            if (strcmp(item->name, node->name) != 0) {
                item->invalidate_cache();
                strcpy_s(item->name, node->name);
            }

            item->node_index = node_idx;
            item->depth = node->depth;
            item->is_folder = node->is_folder;
            item->is_expanded = node->is_expanded;
            item->git_ref_index = node->git_ref_index;
            item->parent_tree = this;

            // Check if current branch
            item->is_current_branch = (!node->is_folder &&
                                        node->git_ref_index == current_branch_idx);
            if (item->is_current_branch) {
                current_branch_flattened_index = (int)i;
            }
        }

        item_count = state->flattened_count;
        if (item_count > MAX_BRANCH_ITEMS) {
            item_count = MAX_BRANCH_ITEMS;
        }

        // Mark for re-layout
        set_dirty();
    }

    void ensure_visible(int index) {
        if (index < 0 || index >= static_cast<int>(item_count)) return;

        float item_height = Sidebar::BRANCH_ITEM_HEIGHT;
        float item_top = index * item_height;
        float item_bottom = item_top + item_height;

        if (external_scroll) {
            // When using external scroll, request parent to scroll
            float list_item_top = rect.y + item_top;
            float list_item_bottom = rect.y + item_bottom;

            float new_scroll_offset = -1.0f;  // -1 means no change needed
            if (list_item_top < viewport_top) {
                // Item is above viewport - scroll up
                new_scroll_offset = item_top;
            } else if (list_item_bottom > viewport_bottom) {
                // Item is below viewport - scroll down
                float viewport_height = viewport_bottom - viewport_top;
                new_scroll_offset = item_bottom - viewport_height;
            }

            if (new_scroll_offset >= 0.0f && on_scroll_request) {
                on_scroll_request(this, new_scroll_offset, scroll_request_user_data);
            }
        }
        set_dirty();
    }

    void set_selection(int index) {
        if (index < 0) index = -1;
        if (index >= static_cast<int>(item_count)) index = static_cast<int>(item_count) - 1;

        if (selected_index != index) {
            selected_index = index;
            set_dirty();
        }
    }

    bool on_key_down(int vk, bool ctrl, bool shift, bool alt) override {
        (void)ctrl; (void)shift; (void)alt;
        if (collapsed || item_count == 0) return false;

        int new_index = selected_index;

        if (vk == VK_UP) {
            if (selected_index <= 0) {
                new_index = 0;
            } else {
                new_index = selected_index - 1;
            }
        } else if (vk == VK_DOWN) {
            if (selected_index < 0) {
                new_index = 0;
            } else if (selected_index < static_cast<int>(item_count) - 1) {
                new_index = selected_index + 1;
            }
        } else if (vk == VK_HOME) {
            new_index = 0;
        } else if (vk == VK_END) {
            new_index = static_cast<int>(item_count) - 1;
        } else if (vk == VK_RETURN || vk == VK_SPACE) {
            // Activate the selected item
            if (selected_index >= 0 && selected_index < static_cast<int>(item_count) && items[selected_index]) {
                BranchTreeItem* item = items[selected_index];
                if (item->is_folder) {
                    // Toggle folder expand/collapse
                    if (on_folder_toggle) {
                        on_folder_toggle(this, item->node_index, user_data);
                    }
                } else if (on_branch_checkout && item->git_ref_index >= 0) {
                    // Checkout branch
                    on_branch_checkout(this, item->git_ref_index, user_data);
                }
                return true;
            }
            return false;
        } else {
            return false;
        }

        if (new_index != selected_index) {
            set_selection(new_index);
            ensure_visible(new_index);
        }
        return true;
    }

    void on_viewport_changed(float vp_top, float vp_bottom) override {
        if (external_scroll) {
            viewport_top = vp_top;
            viewport_bottom = vp_bottom;
        }
    }

private:
    // Note: y is in widget-local coordinates (EventDispatcher converts to local)
    int hit_test_item(float y) const {
        if (collapsed || item_count == 0) return -1;
        if (y < 0) return -1;

        int index = static_cast<int>(y / Sidebar::BRANCH_ITEM_HEIGHT);
        if (index < 0 || index >= static_cast<int>(item_count)) return -1;

        return index;
    }
};

// Out-of-class definitions for BranchTreeItem methods that depend on BranchTree
bool BranchTreeItem::on_mouse_down(float x, float y, int button) {
    // Delegate click handling to parent BranchTree
    if (parent_tree) {
        // Convert to parent-relative coordinates
        float parent_y = rect.y - parent_tree->rect.y + y;
        return parent_tree->on_mouse_down(x, parent_y, button);
    }
    return false;
}

bool BranchTreeItem::on_double_click(float x, float y, int button) {
    // Delegate double-click handling to parent BranchTree
    if (parent_tree) {
        float parent_y = rect.y - parent_tree->rect.y + y;
        return parent_tree->on_double_click(x, parent_y, button);
    }
    return false;
}

// ============================================================================
// StashList Widget
// ============================================================================
// Container widget for rendering stash entries.
// Uses external scroll (parent ScrollContainer provides viewport/scrollbar).

struct StashList : Widget {
    // Data (synced from g_stashes/g_stash_count via rebuild_from_cache).
    // Raised from 64 → 512 for users who hoard stashes.
    static constexpr size_t MAX_STASH_ITEMS = 512;
    int item_count = 0;
    int selected_index = -1;
    int hovered_index = -1;

    // Stash data cache (copied from global state)
    struct StashItemData {
        int index;           // stash@{index}
        wchar_t message[256]; // Stash message for display (matches filename buffer width)
    };
    StashItemData item_data[MAX_STASH_ITEMS] = {};

    // External scroll support (parent ScrollContainer handles scrolling)
    bool external_scroll = true;
    float viewport_top = 0.0f;
    float viewport_bottom = 0.0f;

    // Collapsed state (controlled by parent SectionHeader)
    bool collapsed = false;

    // Double-click detection for applying stash
    DWORD last_click_time = 0;
    int last_click_index = -1;
    static constexpr DWORD DOUBLE_CLICK_TIME = 500;  // ms

    // Callbacks
    void (*on_stash_select)(StashList* list, int index, void* user_data) = nullptr;
    void (*on_stash_apply)(StashList* list, int index, void* user_data) = nullptr;
    void (*on_stash_context_menu)(StashList* list, int stash_index,
                                   float screen_x, float screen_y, void* user_data) = nullptr;
    void* user_data = nullptr;

    // Callback for requesting scroll position change (handled by parent when external_scroll = true)
    void (*on_scroll_request)(StashList* list, float scroll_y, void* user_data) = nullptr;
    void* scroll_request_user_data = nullptr;

    StashList() {
        flags |= WidgetFlags::ClipChildren;
        flags |= WidgetFlags::CapturesMouse;
        flags |= WidgetFlags::Focusable;
    }

    float get_content_height() const {
        if (collapsed) return 0.0f;
        return item_count * Sidebar::BRANCH_ITEM_HEIGHT;
    }

    void measure(const LayoutConstraints& constraints) override {
        if (external_scroll) {
            preferred_height = get_content_height();
        } else if (preferred_height <= 0.0f) {
            preferred_height = constraints.max_height;
        }
        rect.width = constraints.max_width;
        rect.height = preferred_height;
    }

    void layout() override {
        // Items are positioned during render (simple linear layout)
    }

    void render(RenderContext& ctx) override {
        if (collapsed || item_count == 0) return;

        float item_height = Sidebar::BRANCH_ITEM_HEIGHT;
        float y = rect.y;
        float item_left = Theme::PADDING + Sidebar::BRANCH_INDENT;
        float item_right = rect.width - Theme::PADDING;

        for (int i = 0; i < item_count; i++) {
            float item_top = y;
            float item_bottom = y + item_height;

            // Virtualization: skip items outside viewport
            if (item_bottom < viewport_top) {
                y += item_height;
                continue;
            }
            if (item_top > viewport_bottom) break;

            bool is_hovered = (hovered_index == i);
            bool is_selected = (selected_index == i);

            // Background
            D2D1_RECT_F bg_rect = D2D1::RectF(rect.x, item_top, rect.x + rect.width, item_bottom);
            if (is_selected) {
                D2D1_COLOR_F sel_color = color_from_argb(Theme::ACCENT);
                sel_color.a = 0.12f;
                ctx.brush->SetColor(sel_color);
                ctx.target->FillRectangle(bg_rect, ctx.brush);

                // Selection indicator bar
                D2D1_RECT_F bar_rect = D2D1::RectF(rect.x, item_top, rect.x + 2.0f, item_bottom);
                ctx.fill_rect(bar_rect, Theme::SELECTION_BORDER);

                // Focus ring when list has keyboard focus
                if (flags & WidgetFlags::KeyboardFocused) {
                    D2D1_RECT_F focus_rect = D2D1::RectF(
                        rect.x + 2.0f, item_top + 1.0f,
                        rect.x + rect.width - 2.0f, item_bottom - 1.0f);
                    ctx.brush->SetColor(color_from_argb(Theme::ACCENT));
                    D2D1_ROUNDED_RECT rr = { focus_rect, 3.0f, 3.0f };
                    ctx.target->DrawRoundedRectangle(rr, ctx.brush, 2.0f);
                }
            } else if (is_hovered) {
                ctx.fill_rect(bg_rect, Theme::BG_HOVER);
            }

            // Stash label: stash@{N}: message
            wchar_t label[128];
            swprintf_s(label, L"stash@{%d}: %s", item_data[i].index, item_data[i].message);

            uint32_t text_color = (is_hovered || is_selected) ? Theme::TEXT_PRIMARY : Theme::TEXT_SECONDARY;
            ctx.brush->SetColor(color_from_argb(text_color));

            D2D1_RECT_F text_rect = D2D1::RectF(
                rect.x + item_left,
                item_top + 4.0f,
                rect.x + item_right,
                item_bottom
            );

            if (g_text_format_path) {
                ctx.target->DrawText(label, (UINT32)wcslen(label), g_text_format_path,
                    text_rect, ctx.brush, D2D1_DRAW_TEXT_OPTIONS_CLIP);
            }

            y += item_height;
        }
    }

    bool on_mouse_move(float x, float y) override {
        (void)x;

        int new_hovered = hit_test_item(y);
        if (new_hovered != hovered_index) {
            hovered_index = new_hovered;
            set_dirty();
        }
        return true;
    }

    bool on_mouse_down(float x, float y, int button) override {
        (void)x;

        int clicked_index = hit_test_item(y);
        if (clicked_index < 0 || clicked_index >= item_count) {
            return false;
        }

        // Right-click: show context menu
        if (button == 1) {
            // Select the item on right-click
            selected_index = clicked_index;
            set_dirty();

            if (on_stash_context_menu) {
                // Convert to screen coordinates
                POINT pt = { static_cast<LONG>(rect.x + x), static_cast<LONG>(rect.y + y) };
                ClientToScreen(g_main_window, &pt);
                on_stash_context_menu(this, item_data[clicked_index].index,
                                      static_cast<float>(pt.x), static_cast<float>(pt.y), user_data);
            }
            return true;
        }

        if (button != 0) return false;  // Only handle left click for other logic

        DWORD now = GetTickCount();

        // Check for double-click
        if (last_click_index == clicked_index &&
            (now - last_click_time) < DOUBLE_CLICK_TIME) {
            // Double-click: apply stash
            if (on_stash_apply) {
                on_stash_apply(this, item_data[clicked_index].index, user_data);
            }
            last_click_index = -1;
            last_click_time = 0;
        } else {
            // Single click: select and record for potential double-click
            selected_index = clicked_index;
            last_click_index = clicked_index;
            last_click_time = now;

            if (on_stash_select) {
                on_stash_select(this, item_data[clicked_index].index, user_data);
            }
        }

        set_dirty();
        return true;
    }

    bool on_double_click(float x, float y, int button) override {
        (void)x;
        if (button != 0) return false;  // Only handle left click

        int clicked_index = hit_test_item(y);
        if (clicked_index < 0 || clicked_index >= item_count) {
            return false;
        }

        // Double-click: apply stash
        if (on_stash_apply) {
            on_stash_apply(this, item_data[clicked_index].index, user_data);
            // Clear timing state since we handled it
            last_click_index = -1;
            last_click_time = 0;
            return true;
        }

        return false;
    }

    bool on_mouse_leave() override {
        if (hovered_index != -1) {
            hovered_index = -1;
            set_dirty();
        }
        return true;
    }

    void set_collapsed(bool state) {
        if (collapsed != state) {
            collapsed = state;
            set_dirty();
        }
    }

    // Rebuild from global stash cache (called before render)
    void rebuild_from_cache();

    void ensure_visible(int index) {
        if (index < 0 || index >= item_count) return;

        float item_height = Sidebar::BRANCH_ITEM_HEIGHT;
        float item_top = index * item_height;
        float item_bottom = item_top + item_height;

        if (external_scroll) {
            // When using external scroll, request parent to scroll
            float list_item_top = rect.y + item_top;
            float list_item_bottom = rect.y + item_bottom;

            float new_scroll_offset = -1.0f;  // -1 means no change needed
            if (list_item_top < viewport_top) {
                // Item is above viewport - scroll up
                new_scroll_offset = item_top;
            } else if (list_item_bottom > viewport_bottom) {
                // Item is below viewport - scroll down
                float viewport_height = viewport_bottom - viewport_top;
                new_scroll_offset = item_bottom - viewport_height;
            }

            if (new_scroll_offset >= 0.0f && on_scroll_request) {
                on_scroll_request(this, new_scroll_offset, scroll_request_user_data);
            }
        }
        set_dirty();
    }

    void set_selection(int index) {
        if (index < 0) index = -1;
        if (index >= item_count) index = item_count - 1;

        if (selected_index != index) {
            selected_index = index;
            set_dirty();
        }
    }

    bool on_key_down(int vk, bool ctrl, bool shift, bool alt) override {
        (void)ctrl; (void)shift; (void)alt;
        if (collapsed || item_count == 0) return false;

        int new_index = selected_index;

        if (vk == VK_UP) {
            if (selected_index <= 0) {
                new_index = 0;
            } else {
                new_index = selected_index - 1;
            }
        } else if (vk == VK_DOWN) {
            if (selected_index < 0) {
                new_index = 0;
            } else if (selected_index < item_count - 1) {
                new_index = selected_index + 1;
            }
        } else if (vk == VK_HOME) {
            new_index = 0;
        } else if (vk == VK_END) {
            new_index = item_count - 1;
        } else if (vk == VK_RETURN || vk == VK_SPACE) {
            // Apply the selected stash
            if (selected_index >= 0 && selected_index < item_count) {
                if (on_stash_apply) {
                    on_stash_apply(this, item_data[selected_index].index, user_data);
                }
                return true;
            }
            return false;
        } else {
            return false;
        }

        if (new_index != selected_index) {
            set_selection(new_index);
            ensure_visible(new_index);
        }
        return true;
    }

    void on_viewport_changed(float vp_top, float vp_bottom) override {
        if (external_scroll) {
            viewport_top = vp_top;
            viewport_bottom = vp_bottom;
        }
    }

private:
    int hit_test_item(float y) const {
        if (collapsed || item_count == 0) return -1;
        if (y < 0) return -1;

        int index = static_cast<int>(y / Sidebar::BRANCH_ITEM_HEIGHT);
        if (index < 0 || index >= item_count) return -1;

        return index;
    }
};

// rebuild_from_cache implementation (needs access to g_stashes)
// Defined in platform.cpp where g_stashes is accessible
